import scala.collection.immutable.Queue

def solve(n: Long, k: Long): Long = {
  if (k == 0) return 0
  if (k == 1) {
    // Numbers with popcount-depth 1 are those with exactly 1 bit set
    // Count numbers from 1 to n with exactly 1 bit set
    val count = (n.toLong).toBinaryString.length
    return count
  }

  // Precompute the popcount-depth for numbers up to n
  // We use BFS to compute the depth for each number
  val queue = Queue((1, 1)) // (number, depth)
  val visited = scala.collection.mutable.HashSet[Int]()
  val depths = scala.collection.mutable.HashMap[Int, Int]()

  while (queue.nonEmpty) {
    val (num, depth) = queue.dequeue
    if (num > n) continue
    if (visited.contains(num)) continue
    visited.add(num)
    depths(num) = depth

    val nextNum = scala.math.countOneBits(num)
    if (nextNum == 1) {
      queue.enqueue((num, depth + 1))
    } else {
      queue.enqueue((nextNum, depth + 1))
    }
  }

  // Count numbers with popcount-depth exactly k
  var count = 0L
  for (i <- 1 to n.toInt) {
    if (depths.getOrElse(i, 0) == k) count += 1
  }
  count
}
